import { NotificationFeed } from "./NotificationFeed";

export const metadata = {
  title: "通知 · gunjo-test",
};

export default function NotificationsPage() {
  return (
    <main className="min-h-screen bg-background text-foreground">
      <NotificationFeed />
    </main>
  );
}

// Domain model for the activity feed. Note: this is a *richer* shape than
// @gunjo/ui's exported `Notification` ({id,title,description,timestamp,read}),
// because that type has no actor/avatar/type/target fields — see report.

export type ActivityType =
  | "mention"
  | "comment"
  | "reaction"
  | "follow"
  | "system";

export interface Actor {
  name: string;
  /** Avatar image URL; when absent we fall back to initials. */
  avatarUrl?: string;
}

export interface ActivityItem {
  id: string;
  type: ActivityType;
  actor: Actor;
  /** Action verb phrase, e.g. "mentioned you in". */
  action: string;
  /** The thing acted upon, e.g. "Design review #128". */
  target: string;
  /** Optional snippet (comment body, etc.). */
  snippet?: string;
  /** Epoch ms. Stored as a number so relative time is computed deterministically. */
  createdAt: number;
  read: boolean;
}

const MIN = 60_000;
const HOUR = 60 * MIN;
const DAY = 24 * HOUR;

/**
 * Seed data is generated relative to a FIXED reference time passed in, so the
 * server render and the client render agree on the absolute `createdAt` values.
 * (The relative label "2h ago" is then derived on the client only — see
 * useRelativeTime — which is what prevents a hydration mismatch.)
 */
export function makeSeedNotifications(now: number): ActivityItem[] {
  return [
    {
      id: "n1",
      type: "mention",
      actor: { name: "田中 美香", avatarUrl: "https://i.pravatar.cc/80?img=47" },
      action: "があなたをメンションしました：",
      target: "デザインレビュー #128",
      snippet: "@you リリース前に dawn パレットを確認してもらえますか？",
      createdAt: now - 12 * MIN,
      read: false,
    },
    {
      id: "n2",
      type: "comment",
      actor: { name: "佐藤 大輔", avatarUrl: "https://i.pravatar.cc/80?img=12" },
      action: "がコメントしました：",
      target: "PR #2041 · fix(timeline) マーカー修正",
      snippet: "細かい指摘を2つだけ。それ以外はLGTMです 🚀",
      createdAt: now - 95 * MIN,
      read: false,
    },
    {
      id: "n3",
      type: "reaction",
      actor: { name: "丘 そら" },
      action: "があなたのコメントに ❤️ をつけました：",
      target: "#general",
      createdAt: now - 3 * HOUR,
      read: false,
    },
    {
      id: "n4",
      type: "follow",
      actor: { name: "山本 ひかり", avatarUrl: "https://i.pravatar.cc/80?img=32" },
      action: "があなたをフォローしました",
      target: "",
      createdAt: now - 5 * HOUR,
      read: true,
    },
    {
      id: "n5",
      type: "system",
      actor: { name: "Gunjo" },
      action: "のデプロイが成功しました：",
      target: "gunjo-docs · 本番環境",
      snippet: "ビルド a00b860 を47秒でデプロイしました。",
      createdAt: now - 1 * DAY - 2 * HOUR,
      read: false,
    },
    {
      id: "n6",
      type: "comment",
      actor: { name: "藤井 玲奈", avatarUrl: "https://i.pravatar.cc/80?img=5" },
      action: "があなたのスレッドに返信しました：",
      target: "ロードマップ Q3",
      snippet: "NotificationCenter の改修は次のサイクルに回しました。",
      createdAt: now - 1 * DAY - 6 * HOUR,
      read: true,
    },
    {
      id: "n7",
      type: "mention",
      actor: { name: "渡辺 翔", avatarUrl: "https://i.pravatar.cc/80?img=15" },
      action: "があなたをメンションしました：",
      target: "インシデント #77",
      createdAt: now - 4 * DAY,
      read: true,
    },
    {
      id: "n8",
      type: "system",
      actor: { name: "Gunjo" },
      action: "の週次ダイジェストが届きました：",
      target: "@gunjo/ui ワークスペース",
      createdAt: now - 9 * DAY,
      read: true,
    },
  ];
}

"use client";

import * as React from "react";
import {
  Avatar,
  AvatarFallback,
  AvatarImage,
  Badge,
  Button,
  Card,
  CardContent,
  EmptyState,
  Skeleton,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
  NotificationCenter,
  type Notification as GunjoNotification,
} from "@gunjo/ui";
import {
  IconAt,
  IconMessageCircle,
  IconHeart,
  IconUserPlus,
  IconServerBolt,
  IconBellOff,
  IconCheck,
} from "@tabler/icons-react";
import type { ActivityItem, ActivityType } from "./data";
import { makeSeedNotifications } from "./data";
import { formatRelative, absoluteLabel, useNow } from "./useRelativeTime";

/* ---------- type → icon / marker styling ---------- */

const TYPE_META: Record<
  ActivityType,
  { icon: React.ComponentType<{ size?: number; className?: string }>; ring: string; label: string }
> = {
  mention: { icon: IconAt, ring: "bg-primary/15 text-primary", label: "メンション" },
  comment: { icon: IconMessageCircle, ring: "bg-secondary text-secondary-foreground", label: "コメント" },
  reaction: { icon: IconHeart, ring: "bg-destructive/15 text-destructive", label: "リアクション" },
  follow: { icon: IconUserPlus, ring: "bg-success/15 text-success", label: "フォロー" },
  system: { icon: IconServerBolt, ring: "bg-muted text-muted-foreground", label: "システム" },
};

function initials(name: string): string {
  return name
    .split(/\s+/)
    .map((p) => p[0])
    .slice(0, 2)
    .join("")
    .toUpperCase();
}

/* ---------- grouping ---------- */

type GroupKey = "today" | "yesterday" | "earlier";
const GROUP_TITLES: Record<GroupKey, string> = {
  today: "今日",
  yesterday: "昨日",
  earlier: "それ以前",
};

function startOfDay(ms: number): number {
  const d = new Date(ms);
  d.setHours(0, 0, 0, 0);
  return d.getTime();
}

function groupOf(createdAt: number, todayStart: number): GroupKey {
  if (createdAt >= todayStart) return "today";
  if (createdAt >= todayStart - 86_400_000) return "yesterday";
  return "earlier";
}

/* ---------- a single feed row ---------- */

function FeedRow({
  item,
  now,
  onMarkRead,
}: {
  item: ActivityItem;
  now: number | null;
  onMarkRead: (id: string) => void;
}) {
  const meta = TYPE_META[item.type];
  const Glyph = meta.icon;
  const timeLabel = now !== null ? formatRelative(item.createdAt, now) : absoluteLabel(item.createdAt);

  return (
    <TimelineItem
      connector
      marker={
        <span
          className={`flex h-7 w-7 items-center justify-center rounded-full ${meta.ring}`}
          aria-hidden
        >
          <Glyph size={15} />
        </span>
      }
      className={!item.read ? "[&>div:last-child]:rounded-lg [&>div:last-child]:bg-primary/5" : undefined}
    >
      <div className="flex items-start gap-3 pr-1">
        <Avatar className="h-9 w-9">
          {item.actor.avatarUrl ? (
            <AvatarImage src={item.actor.avatarUrl} alt="" />
          ) : null}
          <AvatarFallback>{initials(item.actor.name)}</AvatarFallback>
        </Avatar>

        <div className="min-w-0 flex-1">
          <div className="flex items-start justify-between gap-2">
            <TimelineTitle className="font-normal">
              <span className="font-semibold text-foreground">{item.actor.name}</span>{" "}
              <span className="text-muted-foreground">{item.action}</span>{" "}
              {item.target ? (
                <span className="font-medium text-foreground">{item.target}</span>
              ) : null}
            </TimelineTitle>

            <div className="flex shrink-0 items-center gap-2">
              {!item.read && (
                <span
                  className="h-2 w-2 rounded-full bg-primary"
                  aria-label="未読"
                  role="status"
                />
              )}
              <Badge variant="outline" className="hidden sm:inline-flex">
                {meta.label}
              </Badge>
            </div>
          </div>

          {item.snippet ? (
            <TimelineDescription className="mt-1 line-clamp-2">
              {item.snippet}
            </TimelineDescription>
          ) : null}

          <div className="mt-1.5 flex items-center gap-3">
            <TimelineTime
              dateTime={new Date(item.createdAt).toISOString()}
              suppressHydrationWarning
            >
              {timeLabel}
            </TimelineTime>
            {!item.read && (
              <Button
                variant="ghost"
                size="xs"
                className="h-6 px-2 text-xs text-muted-foreground hover:text-foreground"
                onClick={() => onMarkRead(item.id)}
              >
                <IconCheck size={13} className="mr-1" />
                既読にする
              </Button>
            )}
          </div>
        </div>
      </div>
    </TimelineItem>
  );
}

/* ---------- main feed ---------- */

export function NotificationFeed() {
  // Capture a single deterministic "now" on mount so grouping is stable for
  // the session and identical between initial server HTML and first client
  // render (both render the loading skeleton first; see `loading`).
  const [items, setItems] = React.useState<ActivityItem[] | null>(null);
  const now = useNow();

  // Simulate an async fetch → exercises the loading skeleton + mount-only data.
  React.useEffect(() => {
    const t = setTimeout(() => {
      setItems(makeSeedNotifications(Date.now()));
    }, 650);
    return () => clearTimeout(t);
  }, []);

  const markRead = React.useCallback((id: string) => {
    setItems((prev) =>
      prev ? prev.map((n) => (n.id === id ? { ...n, read: true } : n)) : prev,
    );
  }, []);

  const markAllRead = React.useCallback(() => {
    setItems((prev) => (prev ? prev.map((n) => ({ ...n, read: true })) : prev));
  }, []);

  const clearAll = React.useCallback(() => setItems([]), []);

  const unread = items?.filter((n) => !n.read).length ?? 0;

  // Map our rich items to gunjo's flat Notification shape for the bell popover.
  const bellItems: GunjoNotification[] = React.useMemo(
    () =>
      (items ?? []).map((n) => ({
        id: n.id,
        title: `${n.actor.name} ${n.action} ${n.target}`.trim(),
        description: n.snippet ?? "",
        timestamp: now !== null ? formatRelative(n.createdAt, now) : absoluteLabel(n.createdAt),
        read: n.read,
      })),
    [items, now],
  );

  const grouped = React.useMemo(() => {
    if (!items) return null;
    const todayStart = startOfDay(now ?? Date.now());
    const buckets: Record<GroupKey, ActivityItem[]> = {
      today: [],
      yesterday: [],
      earlier: [],
    };
    for (const it of [...items].sort((a, b) => b.createdAt - a.createdAt)) {
      buckets[groupOf(it.createdAt, todayStart)].push(it);
    }
    return buckets;
  }, [items, now]);

  return (
    <div className="mx-auto w-full max-w-2xl px-4 py-8 sm:px-6">
      {/* Header */}
      <header className="mb-6 flex items-center justify-between gap-3">
        <div className="flex items-center gap-3">
          <h1 className="text-xl font-semibold tracking-tight">通知</h1>
          {unread > 0 && (
            <Badge variant="destructive" aria-label={`未読 ${unread} 件`}>
              {unread}
            </Badge>
          )}
          {/* Live region so screen readers hear the count change after mark-read */}
          <span className="sr-only" role="status" aria-live="polite">
            {items ? `未読の通知が ${unread} 件あります` : "通知を読み込み中"}
          </span>
        </div>

        <div className="flex items-center gap-1">
          <Button
            variant="outline"
            size="sm"
            onClick={markAllRead}
            disabled={!items || unread === 0}
          >
            <IconCheck size={15} className="mr-1.5" />
            すべて既読にする
          </Button>
          {/* gunjo's purpose-built bell popover, fed from the same state */}
          <NotificationCenter
            notifications={bellItems}
            onMarkAsRead={markRead}
            onClearAll={markAllRead}
            labels={{ title: "通知", emptyTitle: "未読の通知はありません" }}
          />
        </div>
      </header>

      {/* Loading skeleton */}
      {!items ? (
        <LoadingSkeleton />
      ) : items.length === 0 ? (
        <EmptyState
          icon={<IconBellOff size={22} />}
          title="通知はありません"
          description="誰かがあなたをメンションしたり、あなたの作業にリアクションすると、ここに表示されます。"
          action={
            <Button
              variant="outline"
              size="sm"
              onClick={() => setItems(makeSeedNotifications(Date.now()))}
            >
              サンプルフィードを再読み込み
            </Button>
          }
        />
      ) : (
        <div className="space-y-7">
          {(Object.keys(GROUP_TITLES) as GroupKey[]).map((key) => {
            const bucket = grouped?.[key] ?? [];
            if (bucket.length === 0) return null;
            return (
              <section key={key} aria-labelledby={`group-${key}`}>
                <h2
                  id={`group-${key}`}
                  className="mb-2 text-xs font-semibold uppercase tracking-wide text-muted-foreground"
                >
                  {GROUP_TITLES[key]}
                </h2>
                <Card>
                  <CardContent className="py-4">
                    <Timeline>
                      {bucket.map((it) => (
                        <FeedRow
                          key={it.id}
                          item={it}
                          now={now}
                          onMarkRead={markRead}
                        />
                      ))}
                    </Timeline>
                  </CardContent>
                </Card>
              </section>
            );
          })}

          <div className="flex justify-center">
            <Button variant="ghost" size="sm" onClick={clearAll}>
              すべて消去
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

function LoadingSkeleton() {
  return (
    <Card>
      <CardContent className="space-y-5 py-5">
        {Array.from({ length: 4 }).map((_, i) => (
          <div key={i} className="flex items-start gap-3">
            <Skeleton shape="circle" className="h-9 w-9" />
            <div className="flex-1 space-y-2 pt-1">
              <Skeleton shape="text" className="w-3/4" />
              <Skeleton shape="text" className="w-1/2" />
            </div>
          </div>
        ))}
      </CardContent>
    </Card>
  );
}

"use client";

import * as React from "react";

/**
 * Returns a relative-time formatter that is HYDRATION-SAFE.
 *
 * Why this is needed: a naive `formatRelative(createdAt, Date.now())` called
 * during render produces different output on the server (build/request time)
 * vs the client (a few ms/min later), which React flags as a hydration
 * mismatch. We avoid it by:
 *   1. Rendering an absolute, deterministic label on the FIRST paint (server +
 *      first client render agree because they don't read the clock).
 *   2. Switching to live relative labels only AFTER mount (useEffect), and
 *      ticking once a minute so "2m ago" stays fresh.
 */
export function formatRelative(createdAt: number, now: number): string {
  const diff = Math.max(0, now - createdAt);
  const sec = Math.floor(diff / 1000);
  const min = Math.floor(sec / 60);
  const hr = Math.floor(min / 60);
  const day = Math.floor(hr / 24);

  if (sec < 45) return "たった今";
  if (min < 60) return `${min}分前`;
  if (hr < 24) return `${hr}時間前`;
  if (day === 1) return "昨日";
  if (day < 7) return `${day}日前`;
  return new Date(createdAt).toLocaleDateString("ja-JP", {
    month: "long",
    day: "numeric",
  });
}

/** Absolute fallback rendered before mount (deterministic, no clock read). */
export function absoluteLabel(createdAt: number): string {
  return new Date(createdAt).toISOString().slice(0, 16).replace("T", " ");
}

export function useNow(intervalMs = 60_000): number | null {
  // null until mounted → callers render the deterministic fallback first.
  const [now, setNow] = React.useState<number | null>(null);
  React.useEffect(() => {
    setNow(Date.now());
    const id = setInterval(() => setNow(Date.now()), intervalMs);
    return () => clearInterval(id);
  }, [intervalMs]);
  return now;
}
